var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainingService>();

var app = builder.Build();

// Train the model at startup and register the prediction engine pool
var trainer = app.Services.GetRequiredService<ModelTrainingService>();
trainer.TrainAndEvaluate();

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

// Rebuild the service provider with the prediction pool registered
// Use a simpler approach: register before building
app = null!;

// Rebuild properly with prediction pool
var builder2 = WebApplication.CreateBuilder(args);
builder2.Services.AddControllers();
builder2.Services.AddSingleton<ModelTrainingService>();
builder2.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(Path.Combine(builder2.Environment.ContentRootPath, "Data", "model.zip"));

var app2 = builder2.Build();

// Train model before accepting requests
var trainingService = app2.Services.GetRequiredService<ModelTrainingService>();
trainingService.TrainAndEvaluate();

app2.MapControllers();
app2.Run();

